mapper.select:
SELECT 
  FROM er.tn_cef_claim cl
 WHERE cl.cef_id   = #{cefId}
   AND cl.claim_no = #{claimNo}
   AND NOW() BETWEEN cl.use_bgng_dt AND cl.use_end_dt

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_cef_claim
 WHERE cef_id   = #{cefId}
   AND claim_no = #{claimNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_cef_claim
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE cef_id   = #{cefId}
   AND claim_no = #{claimNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.select:
SELECT 'CEF' AS source_type, cl.cef_id AS source_id, cl.claim_no AS claim_no, c.oprtr_id AS oprtr_id, o.oprtr_nm AS oprtr_nm, c.rprt_yr AS rprt_yr, cl.pure_fuel_mass AS mass FROM er.tn_cef_claim cl JOIN er.tn_cef c ON c.cef_id = cl.cef_id AND NOW() BETWEEN c.use_bgng_dt AND c.use_end_dt JOIN com.tn_oprtr o ON o.oprtr_id = c.oprtr_id AND NOW() BETWEEN o.use_bgng_dt AND o.use_end_dt WHERE cl.batch_id_no = #{batchIdNo} AND NOW() BETWEEN cl.use_bgng_dt AND cl.use_end_dt
AND NOT (cl.cef_id = #{excludeCefId}
AND cl.claim_no = #{excludeClaimNo}
)
ORDER BY c.oprtr_id, c.rprt_yr, cl.cef_id, cl.claim_no
